class SecureQueryExecutor(spark: SparkSession) {
  
  private val allowedTables = Set(
    "sales_data",
    "customer_data", 
    "product_catalog",
    "transactions",
    "user_events",
    "inventory"
  )
  
  private val blockedKeywords = Set(
    "DROP", "DELETE", "TRUNCATE", "INSERT", "UPDATE",
    "CREATE", "ALTER", "GRANT", "REVOKE", "MERGE"
  )
  
  private val maxResultRows = 10000
  private val defaultTimeout = 300
  
  def executeQuery(request: QueryRequest): QueryResponse = {
    val startTime = System.currentTimeMillis()
    
    Try {
      validateQuery(request.query)
      
      val timeoutSeconds = request.timeoutSeconds.getOrElse(defaultTimeout)
      val maxRows = request.maxRows.getOrElse(1000).min(maxResultRows)
      
      spark.sparkContext.setLocalProperty("spark.sql.execution.timeout", s"${timeoutSeconds}s")
      
      val df = executeWithTimeout(request.query, timeoutSeconds)
      
      val limitedDf = df.limit(maxRows)
      val rows = limitedDf.collect()
      
      val schema = limitedDf.schema.fieldNames
      val data = rows.map { row =>
        schema.zipWithIndex.map { case (fieldName, idx) =>
          fieldName -> (if (row.isNullAt(idx)) null else row.get(idx))
        }.toMap
      }
      
      val executionTime = System.currentTimeMillis() - startTime
      
      QueryResponse(
        success = true,
        data = Some(data),
        schema = Some(schema),
        rowCount = Some(rows.length),
        executionTimeMs = executionTime
      )
      
    } match {
      case Success(response) => response
      case Failure(exception) =>
        val executionTime = System.currentTimeMillis() - startTime
        QueryResponse(
          success = false,
          error = Some(s"Query execution failed: ${exception.getMessage}"),
          executionTimeMs = executionTime
        )
    }
  }
  
  private def validateQuery(query: String): Unit = {
    val upperQuery = query.toUpperCase.trim
    
    blockedKeywords.foreach { keyword =>
      if (upperQuery.contains(keyword)) {
        throw new SecurityException(s"Query contains blocked keyword: $keyword")
      }
    }
    
    if (!upperQuery.startsWith("SELECT") && !upperQuery.startsWith("WITH")) {
      throw new SecurityException("Only SELECT and WITH queries are allowed")
    }
    
    validateTableAccess(query)
    
    validateQueryComplexity(query)
  }
  
  private def validateTableAccess(query: String): Unit = {
    Try {
      val logicalPlan = spark.sessionState.sqlParser.parsePlan(query)
      val tables = extractTables(logicalPlan)
      
      tables.foreach { table =>
        val tableName = table.split("\\.").last.toLowerCase
        if (!allowedTables.contains(tableName)) {
          throw new SecurityException(s"Access to table '$tableName' is not allowed")
        }
      }
    } match {
      case Failure(e: ParseException) =>
        throw new IllegalArgumentException(s"Invalid SQL syntax: ${e.getMessage}")
      case Failure(e) =>
        throw e
      case Success(_) =>
    }
  }
  
  private def extractTables(plan: LogicalPlan): Set[String] = {
    plan.collect {
      case UnresolvedRelation(tableIdentifier, _, _) =>
        tableIdentifier.unquotedString
    }.toSet
  }
  
  private def validateQueryComplexity(query: String): Unit = {
    val joinCount = "(?i)\\bJOIN\\b".r.findAllIn(query).length
    if (joinCount > 5) {
      throw new IllegalArgumentException("Query exceeds maximum allowed joins (5)")
    }
    
    val subqueryCount = "(?i)\\bSELECT\\b".r.findAllIn(query).length - 1
    if (subqueryCount > 3) {
      throw new IllegalArgumentException("Query exceeds maximum allowed subqueries (3)")
    }
  }
  
  private def executeWithTimeout(query: String, timeoutSeconds: Int): DataFrame = {
    val future = scala.concurrent.Future {
      spark.sql(query)
    }(scala.concurrent.ExecutionContext.global)
    
    Try {
      scala.concurrent.Await.result(future, scala.concurrent.duration.Duration(timeoutSeconds, TimeUnit.SECONDS))
    } match {
      case Success(df) => df
      case Failure(_: scala.concurrent.TimeoutException) =>
        throw new RuntimeException(s"Query execution exceeded timeout of $timeoutSeconds seconds")
      case Failure(e) => throw e
    }
  }
}

class DataLakeQueryService(spark: SparkSession) {
  
  private val queryExecutor = new SecureQueryExecutor(spark)
  
  def initializeDataLake(): Unit = {
    spark.sql("CREATE DATABASE IF NOT EXISTS analytics")
    spark.sql("USE analytics")
    
    registerTable("sales_data", "s3a://datalake/sales/")
    registerTable("customer_data", "s3a://datalake/customers/")
    registerTable("product_catalog", "s3a://datalake/products/")
    registerTable("transactions", "s3a://datalake/transactions/")
    registerTable("user_events", "s3a://datalake/events/")
    registerTable("inventory", "s3a://datalake/inventory/")
  }
  
  private def registerTable(tableName: String, path: String): Unit = {
    Try {
      spark.read.parquet(path).createOrReplaceTempView(tableName)
    } match {
      case Success(_) => println(s"Registered table: $tableName")
      case Failure(e) => println(s"Failed to register table $tableName: ${e.getMessage}")
    }
  }
  
  def processQueryRequest(request: QueryRequest): QueryResponse = {
    queryExecutor.executeQuery(request)
  }
  
  def getAvailableTables(): Array[String] = {
    spark.catalog.listTables().collect().map(_.name)
  }
  
  def getTableSchema(tableName: String): Option[Map[String, String]] = {
    Try {
      val df = spark.table(tableName)
      Some(df.schema.fields.map(f => f.name -> f.dataType.simpleString).toMap)
    }.toOption
  }
}

object BigDataAnalyticsPlatform {
  
  def main(args: Array[String]): Unit = {
    val spark = SparkSession.builder()
      .appName("BigDataAnalyticsPlatform")
      .config("spark.sql.adaptive.enabled", "true")
      .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
      .config("spark.sql.cbo.enabled", "true")
      .config("spark.sql.statistics.histogram.enabled", "true")
      .getOrCreate()
    
    val service = new DataLakeQueryService(spark)
    service.initializeDataLake()
    
    val sampleQueries = Array(
      QueryRequest("SELECT * FROM sales_data WHERE sale_date >= '2024-01-01' LIMIT 100"),
      QueryRequest("SELECT customer_id, COUNT(*) as order_count FROM transactions GROUP BY customer_id ORDER BY order_count DESC LIMIT 50"),
      QueryRequest(
        """
          |SELECT 
          |  p.product_name,
          |  SUM(s.quantity) as total_sold,
          |  SUM(s.revenue) as total_revenue
          |FROM sales_data s
          |JOIN product_catalog p ON s.product_id = p.product_id
          |WHERE s.sale_date >= '2024-01-01'
          |GROUP BY p.product_name
          |ORDER BY total_revenue DESC
          |LIMIT 20
        """.stripMargin
      )
    )
    
    sampleQueries.foreach { request =>
      println(s"\nExecuting query: ${request.query.take(100)}...")
      val response = service.processQueryRequest(request)
      
      if (response.success) {
        println(s"Success! Rows returned: ${response.rowCount.getOrElse(0)}")
        println(s"Execution time: ${response.executionTimeMs}ms")
        println(s"Schema: ${response.schema.getOrElse(Array()).mkString(", ")}")
      } else {
        println(s"Error: ${response.error.getOrElse("Unknown error")}")
      }
    }
    
    println("\n=== Available Tables ===")
    service.getAvailableTables().foreach(println)
    
    spark.stop()
  }
}

class QueryAPIHandler(service: DataLakeQueryService) {
  
  def handleQueryRequest(queryString: String, maxRows: Int = 1000, timeout: Int = 300): String = {
    val request = QueryRequest(
      query = queryString,
      maxRows = Some(maxRows),
      timeoutSeconds = Some(timeout)
    )
    
    val response = service.processQueryRequest(request)
    formatResponse(response)
  }
  
  private def formatResponse(response: QueryResponse): String = {
    if (response.success) {
      s"""
         |{
         |  "success": true,
         |  "rowCount": ${response.rowCount.getOrElse(0)},
         |  "executionTimeMs": ${response.executionTimeMs},
         |  "schema": ${response.schema.map(_.mkString("[\"", "\", \"", "\"]")).getOrElse("[]")},
         |  "data": ${formatData(response.data)}
         |}
       """.stripMargin
    } else {
      s"""
         |{
         |  "success": false,
         |  "error": "${response.error.getOrElse("Unknown error")}",
         |  "executionTimeMs": ${response.executionTimeMs}
         |}
       """.stripMargin
    }
  }
  
  private def formatData(data: Option[Array[Map[String, Any]]]): String = {
    data.map { rows =>
      rows.take(10).map { row =>
        row.map { case (k, v) => s""""$k": "${String.valueOf(v)}"""" }.mkString("{", ", ", "}")
      }.mkString("[", ", ", "]")
    }.getOrElse("[]")
  }
}